3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const liveSet = new Set<string>();
5	  for (const [x, y] of cells) {
6	    liveSet.add(key(x, y));
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	
11	  for (const liveKey of liveSet) {
12	    const [x, y] = parseKey(liveKey);
13	    for (let dx = -1; dx <= 1; dx++) {
14	      for (let dy = -1; dy <= 1; dy++) {
15	        if (dx === 0 && dy === 0) continue;
16	        const nx = x + dx;
17	        const ny = y + dy;
18	        const k = key(nx, ny);
19	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
20	      }
21	    }
22	  }
23	
24	  const result: Cell[] = [];
25	
26	  for (const [k, count] of neighborCounts) {
27	    const isAlive = liveSet.has(k);
28	    if (count === 3 || (isAlive && count === 2)) {
29	      const [x, y] = parseKey(k);
30	      result.push([x, y]);
31	    }
32	  }
33	
34	  return result;
35	}
36	
37	function key(x: number, y: number): string {
38	  return `${x},${y}`;
39	}
40	
41	function parseKey(k: string): [number, number] {
42	  const [xs, ys] = k.split(",");
43	  return [Number(xs), Number(ys)];
44	}
